const lead = $input.first().json;
const stage = lead.funnel_stage;
const niche = lead.niche || 'generico';
const nombre = lead.name || '';
const followupCount = lead.followup_count || 0;

// Mapa de lenguaje por nicho
const lang = {
  barbero: { cliente: 'tus clientes', negocio: 'tu barbería', servicio: 'un corte' },
  doctor: { cliente: 'tus pacientes', negocio: 'tu consultorio', servicio: 'una consulta' },
  generico: { cliente: 'tus clientes', negocio: 'tu negocio', servicio: 'una cita' }
};
const l = lang[niche] || lang.generico;

let mensaje = '';
let newStage = null;
let nextFollowupMinutes = null;

switch(stage) {
  case 'instructions_sent':
    // 30 min sin completar demo
    mensaje = nombre 
      ? `Hey ${nombre}! Solo quiero confirmar, ya pudiste escribir @bloom para probar el sistema?\n\nSi tienes alguna duda me dices \ud83d\ude09`
      : `Hey! Solo quiero confirmar, ya pudiste escribir @bloom para probar el sistema?\n\nSi tienes alguna duda me dices \ud83d\ude09`;
    nextFollowupMinutes = 60 * 24; // Siguiente en 24h si no responde
    break;

  case 'demo_completed':
    // Auto-avanzar a reminders_received después de ~24h
    // (el cron avanazará la etapa automáticamente)
    newStage = 'reminders_received';
    // No enviamos mensaje aqui, se enviará en reminders_received
    break;

  case 'reminders_received':
    // Enviar video del dashboard
    mensaje = `Ya viviste la experiencia completa:\n\u2705 Agendaste en menos de un minuto\n\u2705 Recibiste recordatorios autom\u00e1ticos\n\nTodo eso pasa sin que t\u00fa hagas nada\n\nAhora te muestro c\u00f3mo se ve de TU lado \u2014 c\u00f3mo t\u00fa ver\u00edas las citas y c\u00f3mo configurar todo:\n\n[VIDEO_URL_PLACEHOLDER]\n\nSi te interesa activarlo, podemos hacer una videollamada r\u00e1pida de 15 min con Enrique para dejarlo listo. Tengo algunos espacios esta semana\n\nQu\u00e9 dices? \ud83d\udc47`;
    newStage = 'video_sent';
    nextFollowupMinutes = 60 * 48; // Follow-up en 48h
    break;

  case 'video_sent':
    if (followupCount <= 1) {
      // Primer follow-up: 48h
      mensaje = `Qu\u00e9 te pareci\u00f3 el video? Si tienes alguna duda te puedo explicar r\u00e1pido\n\nSi quieres, podemos hacer una videollamada de 15 min para dejarlo configurado \ud83d\ude09`;
      nextFollowupMinutes = 60 * 72; // Siguiente en 72h más
    } else {
      // \u00daltimo follow-up
      mensaje = `Oye, solo para que sepas: hay una prueba gratis de 7 d\u00edas, sin tarjeta\n\nSi en alg\u00fan momento quieres probarlo, escr\u00edbeme y en 10 minutos lo dejamos listo\n\nMucho \u00e9xito! \ud83d\ude4c`;
      // No más follow-ups
      nextFollowupMinutes = null;
    }
    break;

  default:
    // No hacer nada para etapas no contempladas
    break;
}

return [{ json: {
  ...lead,
  mensaje,
  newStage,
  nextFollowupMinutes,
  skip: !mensaje && !newStage
} }];

