UPDATE leads SET next_followup_at = {{ $('Determinar Acción').first().json.nextFollowupMinutes ? "NOW() + INTERVAL '" + $('Determinar Acción').first().json.nextFollowupMinutes + " minutes'" : 'NULL' }}
